def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 0, -2):
                for b in range(1, a + 4):
                    factor = ((ratio - a) ** 6) / (a * b * 0.85 + 1.2)
                    priority += factor * np.sin(ratio * b / (a + 0.5)) * np.exp(-b / (a + 1))
            priority += ((np.exp(ratio - 7) + np.log1p(ratio)) * np.cos(ratio * 1.3)) ** 1.7
        elif 5 < ratio <= 8:
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, 2 * p):
                    term = ((ratio - p) ** 4) * np.cos(ratio * q / 2) / (q + 1)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4) * 3
            if i % 2 == 0:
                for z in range(1, 4):
                    priority += np.sin(ratio * z * i) * 0.9 / (z + 0.5)
        elif 2 <= ratio <= 5:
            s = 0
            for r in range(1, 16):
                s += ((ratio - 2) ** r) / (r * 1.5) * np.sin(r * ratio * 1.2) * ((-1) ** r)
            priority = (s * np.cos(6.5 * ratio)) - np.log(ratio + 0.1) * 7 + np.tanh(5 * (5 - ratio)) * 2
            if bin_cap < item * 2:
                for c in range(1, 5):
                    priority += np.exp(-c * ratio) * np.cos(c * i * 0.8) * 1.1
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 0.3) * np.cos(n * ratio * 2.5)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 3.5
            else:
                penalty = np.sin(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.03))
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 1.3) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3.5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 2) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.5)
            for j in range(1, 7):
                priority += ((1 - ratio) ** j) * np.cos(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 14):
                s += ((0.5 - ratio) ** k) / (k * 2.5) * np.sin(k * ratio * 3)
            priority = s + 1 / (bin_cap + 2)
            if int(item * 1.7) % 3 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 5) * np.sin(item * m * 1.4)
        else:
            s = 0
            for t in range(1, 13):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.cos(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 4 == 0:
                priority *= 3.8
            else:
                priority /= 3.8
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 3) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.sin(item * u * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6
            for v in range(1, 5):
                priority += np.cos(v * i * ratio) * v * 0.3
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5
            for w in range(1, 4):
                if (i + w) % 2 == 0:
                    priority += np.sin(ratio * (i + w) * 2) * 0.5
                else:
                    priority -= np.cos(ratio * (i + w) * 2) * 0.5
        for idx in range(1, 5):
            mod_val = (i * idx + int(item * 2.2)) % 5
            if mod_val == 0:
                priority += np.sin(ratio * (i + idx + 1)) * 0.4
            elif mod_val == 1:
                priority -= np.cos(ratio * (i - idx)) * 0.4
            else:
                priority += np.tanh(ratio * (idx + i)) * 0.3
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.9
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.9
        priorities[i] = priority
    return priorities
